    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    dimensions_not_applicable boolean DEFAULT false NOT NULL,
    documents_setup_complete boolean DEFAULT false NOT NULL,
    module_setup_visited jsonb,
    environment character varying(20) DEFAULT 'live'::character varying NOT NULL,
    parent_tenant_id uuid,
    lifecycle_status character varying(50) DEFAULT 'in_implementation'::character varying NOT NULL,
    test_data_retention_days integer,
    pre_suspension_status character varying(50),
    suppress_outbound_email boolean DEFAULT true NOT NULL
);


--
-- Name: user_roles; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.user_roles (
    id uuid NOT NULL,
    user_tenant_id uuid NOT NULL,
    role_id uuid NOT NULL,
    assigned_at timestamp with time zone DEFAULT now() NOT NULL,
    assigned_by_id uuid,
    revoked_at timestamp with time zone
);


--
-- Name: user_tenants; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.user_tenants (
    id uuid NOT NULL,
    user_id uuid NOT NULL,
    tenant_id uuid,
    password_hash character varying(255) NOT NULL,
    is_active boolean NOT NULL,
    failed_login_attempts integer NOT NULL,
    locked_until timestamp with time zone,
    last_login_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    role_tier character varying(50)
);


--
-- Name: users; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.users (
    id uuid NOT NULL,
    email character varying(255) NOT NULL,
    full_name character varying(255) NOT NULL,
    account_type public.accounttype NOT NULL,
    is_active boolean NOT NULL,
    is_super_admin boolean NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    employee_code character varying(100),
    department character varying(255),
    job_title character varying(255),
    phone character varying(50),
    first_name character varying(100),
    totp_secret character varying(64),
    totp_enabled boolean DEFAULT false NOT NULL
);


